var ezr_ch_3_Verses = [
  {num:1,words:[["Ua oo i le masina e fitu, ua i ai foi le fanauga a Isaraelu i o latou aai,", "And when the seventh month was come,"], ["ona faapotopoto ai lea o le nuu,", "and the children of Israel were in the cities,"], ["e pei o se tagata e toatasi, i Ierusalema.", "the people gathered themselves together as one man to Jerusalem."]]},
  {num:2,words:[["Ona tutu mai lea o Iosua le atalii o Iosataka,", "Then stood up Jeshua the son of Jozadak,"], ["ma ona uso le au faitaulaga,", "and his brethren the priests,"], ["ma Serupapelu le atalii o Salatielu,", "and Zerubbabel the son of Shealtiel,"], ["ma ona uso,", "and his brethren,"], ["ona latou ati ae lea o le fata faitaulaga o le Atua o Isaraelu,", "and builded the altar of the God of Israel,"], ["ina ia fai ai i ona luga o taulaga,", "to offer burnt offerings thereon,"], ["e pei ona tusia i le tulafono a Mose le tagata o le Atua.", "as it is written in the law of Moses the man of God."]]},
  {num:3,words:[["Ua latou faatuina le fata faitaulaga i ona faavae;", "And they set the altar upon his bases;"], ["aua ua latou matatau i tagata o ia nuu;", "for fear was upon them because of the people of those countries:"], ["ona latou fai taulaga ai lea i ona luga i taulaga mu ia Ieova;", "and they offered burnt offerings thereon unto the LORD,"], ["o taulaga mu i le taeao ma le afiafi.", "even burnt offerings morning and evening."]]},
  {num:4,words:[["Ua faia foi e i latou le tausamiga o fale apitaga,", "They kept also the feast of tabernacles,"], ["e pei ona tusia,", "as it is written,"], ["ma taulaga mu o lea aso ma lea aso e tusa ma le faitau,", "and offered the daily burnt offerings by number,"], ["e tusa ma le tu,", "according to the custom,"], ["o le aso ma le mea e fai ai;", "as the duty of every day required;"]]},
  {num:5,words:[["e mulimuli ane foi o taulaga mu e le aunoa e faia i masina faatoa vaaia,", "And afterward offered the continual burnt offering,"], ["atoa ma tausamiga uma o Ieova na faapaiaina,", "both of the new moons, and of all the set feasts of the LORD that were consecrated,"], ["atoa ma taulaga a tagata uma ua manatu i ai o latou loto e fai ia Ieova.", "and of every one that willingly offered a freewill offering unto the LORD."]]},
  {num:6,words:[["O le aso muamua o le masina e fitu ua latou amata ai ona fai taulaga mu ia Ieova, a o le malumalu o Ieova e lei faavaeina.", "From the first day of the seventh month began they to offer burnt offerings unto the LORD. But the foundation of the temple of the LORD was not yet laid."]]},
  {num:7,words:[["Ua latou avatua ario i e talai maa ma tufuga;", "They gave money also unto the masons,"], ["ma mea e 'ai,", "and to the carpenters;"], ["ma mea e inu,", "and meat,"], ["ma suāuu,", "and drink,"], ["i tagata Saitonu,", "and oil, unto them of Zidon,"], ["ma tagata Turo,", "and to them of Tyre,"], ["latou te aveifoa laau o arasi mai Lepanona i le sami o Iopa,", "to bring cedar trees from Lebanon to the sea of Joppa,"], ["e pei ona pule mai ia te i latou e Kuresa le tupu o Peresia.", "according to the grant that they had of Cyrus king of Persia."]]},
  {num:8,words:[["O le lua o tausaga talu ona latou oo mai i le fale o le Atua i Ierusalema,", "Now in the second year of their coming unto the house of God at Jerusalem,"], ["o le lua o masina,", "in the second month,"], ["ua amata ai e Serupapelu le atalii o Salatielu,", "began Zerubbabel the son of Shealtiel,"], ["ma Iosua le atalii o Iosataka,", "and Jeshua the son of Jozadak,"], ["ma e ua totoe o latou uso le au faitaulaga ma sa Levi,", "and the remnant of their brethren the priests and the Levites,"], ["ma e ua o mai uma mai le tafeaga i Ierusalema,", "and all they that were come out of the captivity unto Jerusalem;"], ["ma latou tofia sa Levi,", "and appointed the Levites,"], ["e afua i e ua luafulu o latou tausaga ma e ua matutua ai,", "from twenty years old and upward,"], ["e pule i le galuega o le fale o Ieova.", "to set forward the work of the house of the LORD."]]},
  {num:9,words:[["Ona tutu mai lea faatasi o Iosua,", "Then stood Jeshua with his sons and his brethren,"], ["o ona atalii,", "Kadmiel and his sons,"], ["ma ona uso,", "the sons of Judah,"], ["o Katameeli ma ona atalii, o le fanauga a Iuta,", "together,"], ["e pule i le faiga o le galuega o le fale o le Atua;", "to set forward the workmen in the house of God:"], ["o atalii o Henatati,", "the sons of Henadad,"], ["o latou atalii ma o latou uso o sa Levi.", "with their sons and their brethren the Levites."]]},
  {num:10,words:[["Ua faavaeina e tufuga ati fale le malumalu o Ieova,", "And when the builders laid the foundation of the temple of the LORD,"], ["ona latou tofia lea o le au faitaulaga ua oofu i latou,", "they set the priests in their apparel with trumpets,"], ["ua i ai foi pu,", "and the Levites the sons of Asaph with cymbals,"], ["ma sa Levi o le fanauga a Asafo ua i ai sumepalo,", "to praise the LORD,"], ["e vivii atu ia Ieova e tusa ma le pule a Tavita le tupu o Isaraelu.", "after the ordinance of David king of Israel."]]},
  {num:11,words:[["Sa latou pepese i viiga ma faafetai ia Ieova,", "And they sang together by course in praising and giving thanks unto the LORD;"], ["aua e lelei o ia,", "because he is good,"], ["aua e faavavau lona alofa ia Isaraelu.", "for his mercy endureth for ever toward Israel."], ["Ona alaga lea o le nuu uma i le alaga tele i viiga ia Ieova,", "And all the people shouted with a great shout, when they praised the LORD,"], ["ona ua faavaeina o le fale o Ieova.", "because the foundation of the house of the LORD was laid."]]},
  {num:12,words:[["E toatele o le au faitaulaga,", "But many of the priests and Levites and chief of the fathers,"], ["ma sa Levi,", "who were ancient men,"], ["ma matai sili e na toeaina,", "that had seen the first house,"], ["na latou vaaia le uluai fale,", "when the foundation of this house was laid before their eyes,"], ["sa fetagisi ma le leo tele ina ua faavaeina o lenei fale i o latou luma;", "wept with a loud voice;"], ["e toatele foi na alalaga ona o le fiafia ua leo tetele.", "and many shouted aloud for joy:"]]},
  {num:13,words:[["Ua le iloga e le nuu le leo o le alaga o le fiafia ma le leo o le fetagisi o le nuu;", "So that the people could not discern the noise of the shout of joy from the noise of the weeping of the people:"], ["aua sa alalaga le nuu i le alaga tele,", "for the people shouted with a loud shout,"], ["ua lagona atu le leo i le mea mamao.", "and the noise was heard afar off."]]},
];
renderVerseSet(ezr_ch_3_Verses, 'ezr-ch3-verses');

var ezr_ch_4_Verses = [
  {num:1,words:[["Ua faalogo e na ita mai ia Iuta ma Peniamina ua faia e tagata o le tafeaga le malumalu mo Ieova le Atua o Isaraelu;", "Now when the adversaries of Judah and Benjamin heard that the children of the captivity builded the temple unto the LORD God of Israel;"]]},
  {num:2,words:[["ona latou o mai lea ia Serupapelu ma matai sili,", "Then they came to Zerubbabel,"], ["ma ua latou faapea mai ia te i latou,", "and to the chief of the fathers,"], ["Se'i tatou faia ia le fale faatasi ma outou;", "and said unto them,"], ["aua ua matou saili atu i lo outou Atua,", "Let us build with you:"], ["pei o outou;", "for we seek your God,"], ["o i matou foi ua matou fai taulaga ia te ia,", "as ye do;"], ["talu ona po o Esarata le tupu o Asuria,", "and we do sacrifice unto him since the days of Esar-haddon king of Assur,"], ["o le na aveina ae i matou iinei.", "which brought us up hither."]]},
  {num:3,words:[["Ona fai atu lea o Serupapelu,", "But Zerubbabel,"], ["ma Iosua,", "and Jeshua,"], ["ma matai sili uma o Isaraelu ia te i latou,", "and the rest of the chief of the fathers of Israel, said unto them,"], ["Tatou te le faia le fale o lo matou Atua ma outou;", "Ye have nothing to do with us to build an house unto our God;"], ["na o i matou nei lava matou te faia le fale o Ieova le Atua o Isaraelu,", "but we ourselves together will build unto the LORD God of Israel,"], ["pei ona fetalai mai le tupu o Kuresa le tupu o Peresia ia te i matou.", "as king Cyrus the king of Persia hath commanded us."]]},
  {num:4,words:[["Ona faavaivaia lea o tagata o Iuta e tagata o le nuu,", "Then the people of the land weakened the hands of the people of Judah,"], ["ma latou faaatuatuvaleina i latou a o faia le fale;", "and troubled them in building,"]]},
  {num:5,words:[["ua latou faaoloaina foi ni e faulalo e faalavelave ia te i latou,", "And hired counsellors against them,"], ["ina ia faaleaogaina ai la latou filifiliga,", "to frustrate their purpose,"], ["i aso uma o Kuresa le tupu o Peresia,", "all the days of Cyrus king of Persia,"], ["e oo foi i le nofoaiga a Tariu le tupu o Peresia.", "even until the reign of Darius king of Persia."]]},
  {num:6,words:[["O le nofoaiga a Asueru,", "And in the reign of Ahasuerus,"], ["o le amataga o lana nofoaiga,", "in the beginning of his reign,"], ["ua tusi atu ai e i latou e momoli i e ua nonofo i Iuta ma Ierusalema.", "wrote they unto him an accusation against the inhabitants of Judah and Jerusalem."]]},
  {num:7,words:[["O ona aso foi o Aretaseta sa tusi atu ai Piselama,", "And in the days of Artaxerxes wrote Bishlam,"], ["o Metereta,", "Mithredath,"], ["o Taveele,", "Tabeel,"], ["ma i latou uma e na pule faatasi ma i latou,", "and the rest of their companions,"], ["ia Aretaseta le tupu o Peresia;", "unto Artaxerxes king of Persia;"], ["o upu foi o le tusi sa tusi i le gagana a Arama,", "and the writing of the letter was written in the Syrian tongue,"], ["sa faamatalaina foi i le gagana a Arama.", "and interpreted in the Syrian tongue."]]},
  {num:8,words:[["Ua tusi atu Rekumu le faamasino, ma Semesai le tusiupu, se tusi e momoli ai Ierusalema ia Aretaseta le tupu, ua faapea;", "Rehum the chancellor and Shimshai the scribe wrote a letter against Jerusalem to Artaxerxes the king in this sort:"]]},
  {num:9,words:[["ona tusi atu lea o Rekumu le faamasino,", "Then wrote Rehum the chancellor,"], ["ma Semesai le tusiupu,", "and Shimshai the scribe,"], ["ma i latou uma e na pule faatasi ma i laua;", "and the rest of their companions;"], ["o tagata o Tinai,", "the Dinaites,"], ["ma tagata o Afareseka,", "the Apharsathchites,"], ["o tagata o Tarepelai,", "the Tarpelites,"], ["o tagata o Afaresai,", "the Apharsites,"], ["o tagata o Areka,", "the Archevites,"], ["o tagata o Papelonia,", "the Babylonians,"], ["o tagata o Susana,", "the Susanchites,"], ["o tagata o Tiavei,", "the Dehavites,"], ["o tagata o Elama,", "and the Elamites,"]]},
  {num:10,words:[["ma isi nuu uma na aumaia e Asenapa,", "And the rest of the nations whom the great and noble Asnappar brought over,"], ["o le alii tele ma le ta'ua,", "and set in the cities of Samaria,"], ["ma na faanofoina i latou i aai o Samaria, ma i latou uma o i ona tala mai o le vaitafe,", "and the rest that are on this side the river,"], ["o ona po foi na tusi ai.", "and at such a time."]]},
  {num:11,words:[["O le ata lenei o le tusi na avatu e i latou ia te ia,", "This is the copy of the letter that they sent unto him,"], ["o le tupu o Aretaseta,", "even unto Artaxerxes the king;"], ["O au auauna o tagata o i ona tala mai o le vaitafe,", "Thy servants the men on this side the river,"], ["ua faapea atu,", "and at such a time."]]},
  {num:12,words:[["Ia silafia e le tupu,", "Be it known unto the king,"], ["o tagata o Iuta e na o ae ia te i matou mai ia te oe,", "that the Jews which came up from thee to us are come unto Jerusalem,"], ["ua oo mai i latou i Ierusalema le aai fouvale ma le matua leaga, ua toe faia,", "building the rebellious and the bad city,"], ["ma ona pa ua faauma,", "and have set up the walls thereof,"], ["ua soo foi ona faavae.", "and joined the foundations."]]},
  {num:13,words:[["Ia silafia nei e le tupu,", "Be it known now unto the king,"], ["afai e toe faia lenei aai,", "that,"], ["a faaumaina foi ona pa,", "if this city be builded,"], ["ona le avatu lea e i latou o taulaga,", "and the walls set up again, then will they not pay toll,"], ["ma taulaga i mea eseese,", "tribute,"], ["ma taulaga o ala;", "and custom,"], ["ona iu ai lea ina faaitiitiina mea a tupu.", "and so thou shalt endamage the revenue of the kings."]]},
  {num:14,words:[["O lenei, ona ua aai i matou i mea mai le maota o le tupu ,", "Now because we have maintenance from the king's palace,"], ["e le tatau ia i matou ona vaai i le faamativaina o le tupu;", "and it was not meet for us to see the king's dishonour,"], ["o le mea lea ua matou aauina atu ai nisi , ma matou faailoa atu ai i le tupu;", "therefore have we sent and certified the king;"]]},
  {num:15,words:[["ina ia suesuea i le tusi a ou tama e faamanatu a'i,", "That search may be made in the book of the records of thy fathers:"], ["ona e maua ai lea i le tusi e faamanatu a'i,", "so shalt thou find in the book of the records,"], ["ma e silafia ai,", "and know that this city is a rebellious city,"], ["o lenei aai o le aai fouvale ma le ua leaga ai mea a tupu ma itu malo,", "and hurtful unto kings and provinces,"], ["ma latou faatupuina ai le fouvale talu anamua lava;", "and that they have moved sedition within the same of old time:"], ["o lea na faaumatia ai lenei aai.", "for which cause was this city destroyed."]]},
  {num:16,words:[["Ua matou faailoa atu i le tupu,", "We certify the king that,"], ["afai e toe faia lenei aai,", "if this city be builded again,"], ["ma faaumaina ona pa,", "and the walls thereof set up,"], ["ona le toe ai lea sou tofi i lenei itu o le vaitafe.", "by this means thou shalt have no portion on this side the river."]]},
  {num:17,words:[["Ona au mai lea e le tupu le tusi ia Rekumu le faamasino,", "Then sent the king an answer unto Rehum the chancellor,"], ["ma Semesai le tusiupu,", "and to Shimshai the scribe,"], ["ma i latou uma ua pule faatasi ma i laua o e nonofo i Samaria,", "and to the rest of their companions that dwell in Samaria,"], ["ma e o i lela itu o le vaitafe,", "and unto the rest beyond the river,"], ["Ia manuia outou ,", "Peace,"], ["o ona po foi na tusi ai .", "and at such a time."]]},
  {num:18,words:[["O le tusi na au mai e outou ia te i matou ua faitauina lava i o'u luma.", "The letter which ye sent unto us hath been plainly read before me."]]},
  {num:19,words:[["Ona ou fai atu ai lea,", "And I commanded,"], ["ona suesuea lea,", "and search hath been made,"], ["ua iloa ai foi o lena aai ua faamaualuga i tupu talu anamua lava,", "and it is found that this city of old time hath made insurrection against kings,"], ["ua faatupuina ai foi le fouvale ma le 'āna'āna.", "and that rebellion and sedition have been made therein."]]},
  {num:20,words:[["Sa i ai foi i Ierusalema o tupu lima malolosi o e na pule i nuu uma i ona tala atu o le vaitafe,", "There have been mighty kings also over Jerusalem, which have ruled over all countries beyond the river;"], ["sa avatua foi ia te i latou o taulaga,", "and toll,"], ["ma taulaga i mea eseese,", "tribute,"], ["ma taulaga o ala.", "and custom, was paid unto them."]]},
  {num:21,words:[["O lenei,", "Give ye now commandment to cause these men to cease,"], ["ina poloai atu ia o outou ia vaoia ia tagata, aua foi ne'i faia lena aai,", "and that this city be not builded,"], ["seia ou tuuina atu se tasi poloaiga.", "until another commandment shall be given from me."]]},
  {num:22,words:[["Ia outou, ne'i outou faatamala i lenei mea;", "Take heed now that ye fail not to do this:"], ["pe se a ea e tupu ai se leaga e faaitiitiina ai mea a tupu.", "why should damage grow to the hurt of the kings?"]]},
  {num:23,words:[["Ua faitauina le upu o le tusi a le tupu o Aretaseta i luma o Rekumu ma Semesai le tusiupu,", "Now when the copy of king Artaxerxes' letter was read before Rehum,"], ["ma e na pule faatasi ma i laua,", "and Shimshai the scribe,"], ["ona latou o ai lea ua tele vavave i Ierusalema,", "and their companions,"], ["i tagata o Iuta,", "they went up in haste to Jerusalem unto the Jews,"], ["ma latou vaoia i latou i le lima malosi.", "and made them to cease by force and power."]]},
  {num:24,words:[["Ona tuua ai lea o le galuega o le fale o le Atua o i Ierusalema. Ua tuua foi ua oo i le lua o tausaga o le nofoaiga a Tariu le tupu o Peresia.", "Then ceased the work of the house of God which is at Jerusalem. So it ceased unto the second year of the reign of Darius king of Persia."]]},
];
renderVerseSet(ezr_ch_4_Verses, 'ezr-ch4-verses');

var ezr_ch_5_Verses = [
  {num:1,words:[["O Hakai le perofeta,", "Then the prophets,"], ["ma Sakaria le atalii o Ito,", "Haggai the prophet,"], ["o perofeta ia sa perofeta ane i le suafa o le Atua o Isaraelu i tagata o Iuta,", "and Zechariah the son of Iddo, prophesied unto the Jews that were in Judah and Jerusalem in the name of the God of Israel,"], ["o i latou lava e na i Iuta ma Ierusalema.", "even unto them."]]},
  {num:2,words:[["Ona tutu ai lea o Serupapelu le atalii o Salatielu,", "Then rose up Zerubbabel the son of Shealtiel,"], ["ma Iosua le atalii o Iosataka,", "and Jeshua the son of Jozadak,"], ["ma amataina ona fai o le fale o le Atua o i Ierusalema;", "and began to build the house of God which is at Jerusalem:"], ["sa ia te i laua foi perofeta a le Atua e lagolago ia te i laua.", "and with them were the prophets of God helping them."]]},
  {num:3,words:[["O ona po lava ia na o mai ai ia te i latou o Tatenai le alii e pule i ona tala mai o le vaitafe,", "At the same time came to them Tatnai,"], ["ma Setaraosenai,", "governor on this side the river,"], ["ma e na pule faatasi ma i laua,", "and Shethar-boznai,"], ["ua fai mai ia te i latou,", "and their companions,"], ["ua faapea mai,", "and said thus unto them,"], ["Po o ai na na poloai atu ia te outou tou te faia lenei fale,", "Who hath commanded you to build this house,"], ["ma faaumaina lenei pa?", "and to make up this wall?"]]},
  {num:4,words:[["Ona matou fai atu lea ia te i latou, ua faapea atu,", "Then said we unto them after this manner,"], ["O igoa lava ia o tagata o faia lenei fale.", "What are the names of the men that make this building?"]]},
  {num:5,words:[["A ua silasila lo latou Atua i toeaina o Iuta,", "But the eye of their God was upon the elders of the Jews,"], ["ua latou le mavaoia i latou,", "that they could not cause them to cease,"], ["seia oo atu le mea ia Tariu;", "till the matter came to Darius:"], ["ona latou tali mai lea i lea mea i le tusi.", "and then they returned answer by letter concerning this matter."]]},
  {num:6,words:[["O le ata lenei o le tusi a Tatenai le alii e pule i ona tala mai o le vaitafe,", "The copy of the letter that Tatnai,"], ["ma Setara-posenai,", "governor on this side the river,"], ["ma e na pule faatasi ma ia,", "and Shethar-boznai,"], ["o tagata o Afareseka,", "and his companions the Apharsachites,"], ["o i ona tala mai o le vaitafe,", "which were on this side the river,"], ["na latou avatua ia Tariu le tupu.", "sent unto Darius the king:"]]},
  {num:7,words:[["Ua latou avatua le tusi ia te ia,", "They sent a letter unto him,"], ["ua tusia faapea foi i totonu,", "wherein was written thus; Unto Darius the king,"], ["Ia ia Tariu le tupu le manuia uma.", "all peace."]]},
  {num:8,words:[["Ia silafia e le tupu na matou o atu i le itu malo o Iuta,", "Be it known unto the king,"], ["i le fale o le Atua silisili,", "that we went into the province of Judea,"], ["o loo faia i maa tetele,", "to the house of the great God, which is builded with great stones,"], ["ma laau ua tuu i ona pa;", "and timber is laid in the walls,"], ["o lenei galuega foi na faia ma le faamalosi,", "and this work goeth fast on,"], ["ma ua manuia i o latou lima.", "and prospereth in their hands."]]},
  {num:9,words:[["Ona matou fesili atu lea i na toeaina,", "Then asked we those elders,"], ["ua faapea atu ia te i latou,", "and said unto them thus,"], ["Po o ai na fai atu ia te outou tou te faia lenei fale,", "Who commanded you to build this house,"], ["ma faaumaina nei pa?", "and to make up these walls?"]]},
  {num:10,words:[["Na matou fesili atu foi ia te i latou i o latou igoa e faailoa atu ia te oe,", "We asked their names also, to certify thee,"], ["ina ia tusi atu ai igoa o tagata e sili ia te i latou.", "that we might write the names of the men that were the chief of them."]]},
  {num:11,words:[["Ua faapea foi ona latou tali mai ia te i matou,", "And thus they returned us answer,"], ["ua fai mai,", "saying,"], ["O i matou o auauna a le Atua o le lagi ma le lalolagi,", "We are the servants of the God of heaven and earth,"], ["ua matou fai foi le fale sa faia i ona tausaga anamua ua tele;", "and build the house that was builded these many years ago,"], ["o le tupu tele i Isaraelu sa na faia ma faaumaina ai.", "which a great king of Israel builded and set up."]]},
  {num:12,words:[["Peitai na faatupuina e o matou tamā le toasa o le Atua o le lagi,", "But after that our fathers had provoked the God of heaven unto wrath,"], ["ona ia tuuina atu ai lea o i latou i le lima o Nepukanesa le tupu o Papelonia,", "he gave them into the hand of Nebuchadnezzar the king of Babylon,"], ["le Kaletaia,", "the Chaldean,"], ["na ia faaumatia foi lenei fale,", "who destroyed this house,"], ["ma tāfea le nuu i Papelonia.", "and carried the people away into Babylon."]]},
  {num:13,words:[["A o le tausaga muamua o Kuresa le tupu o Papelonia, na poloai mai ai Kuresa le tupu ia faia lenei fale o le Atua.", "But in the first year of Cyrus the king of Babylon the same king Cyrus made a decree to build this house of God."]]},
  {num:14,words:[["O mea foi o auro ma ario sa i le fale o le Atua,", "And the vessels also of gold and silver of the house of God,"], ["na avea e Nepukanesa ai le malumalu na i Ierusalema,", "which Nebuchadnezzar took out of the temple that was in Jerusalem,"], ["ua ia aveina atu i le malumalu i Papelonia,", "and brought them into the temple of Babylon, those did Cyrus the king take out of the temple of Babylon,"], ["ua au mai e Kuresa le tupu o ia mea ai le malumalu i Papelonia,", "and they were delivered unto one,"], ["ma ia tuuina atu ai ia Sesepasara,", "whose name was Sheshbazzar,"], ["o le igoa lea o le alii e pule na tofia e ia;", "whom he had made governor;"]]},
  {num:15,words:[["ma ua faapea atu ia te ia,", "And said unto him,"], ["Ina ave ia e oe o nei mea,", "Take these vessels,"], ["ina alu ia,", "go,"], ["ma avatu ai i le malumalu o i Ierusalema,", "carry them into the temple that is in Jerusalem,"], ["ma ia faia le fale o le Atua i lona tulafale.", "and let the house of God be builded in his place."]]},
  {num:16,words:[["Ona sau lea o lena Sesepasara, sa tuu e ia le faavae o le fale o le Atua o i Ierusalema;", "Then came the same Sheshbazzar,"], ["talu foi ia ona po,", "and laid the foundation of the house of God which is in Jerusalem:"], ["ua oo mai i ona po nei,", "and since that time even until now hath it been in building,"], ["ua fai ai pea le fale, a e lei uma.", "and yet it is not finished."]]},
  {num:17,words:[["O lenei,", "Now therefore,"], ["afai e lelei i le tupu,", "if it seem good to the king, let there be search made in the king's treasure house,"], ["ia suesuea i le fale oloa o le tupu o iina i Papelonia,", "which is there at Babylon,"], ["pe moni na poloai Kuresa le tupu ia faia lenei fale o le Atua i Ierusalema;", "whether it be so, that a decree was made of Cyrus the king to build this house of God at Jerusalem,"], ["ma ia tusia mai ia te i matou le finagalo o le tupu i lenei mea.", "and let the king send his pleasure to us concerning this matter."]]},
];
renderVerseSet(ezr_ch_5_Verses, 'ezr-ch5-verses');

var ezr_ch_6_Verses = [
  {num:1,words:[["Ona poloai atu lea o Tariu le tupu,", "Then Darius the king made a decree, and search was made in the house of the rolls,"], ["ona latou suesue lea i le fale tusi na tuuina ai oloa i Papelonia.", "where the treasures were laid up in Babylon."]]},
  {num:2,words:[["Ona maua lea i Akemeta i le 'olo o i le itu malo o Metai le tusi taai,", "And there was found at Achmetha, in the palace that is in the province of the Medes,"], ["ua faapea foi ona tusia i ona totonu le upu e faamanatu a'i,", "a roll, and therein was a record thus written:"]]},
  {num:3,words:[["O le tausaga muamua o Kuresa le tupu ua poloai atu ai Kuresa le tupu i le fale o le Atua i Ierusalema,", "In the first year of Cyrus the king the same Cyrus the king made a decree concerning the house of God at Jerusalem,"], ["Ia faia le fale,", "Let the house be builded,"], ["o le mea na latou fai ai taulaga,", "the place where they offered sacrifices,"], ["ma ia atiina ae ona faavae;", "and let the foundations thereof be strongly laid;"], ["e onogafulu o kupita lona maualuga,", "the height thereof threescore cubits,"], ["e onogafulu o kupita lona lautele;", "and the breadth thereof threescore cubits;"]]},
  {num:4,words:[["e tolu atu maa tetele,", "With three rows of great stones,"], ["ma le atu laau fou;", "and a row of new timber:"], ["ma ia avatua le totogi ai le fale o le tupu;", "and let the expenses be given out of the king's house:"]]},
  {num:5,words:[["o mea foi o auro ma ario o le fale o le Atua na avea e Nepukanesa ai le malumalu o i Ierusalema,", "And also let the golden and silver vessels of the house of God,"], ["na na au mai foi i Papelonia,", "which Nebuchadnezzar took forth out of the temple which is at Jerusalem, and brought unto Babylon,"], ["ia toe avatua,", "be restored,"], ["ma ia tuu atu i le malumalu o i Ierusalema,", "and brought again unto the temple which is at Jerusalem, every one to his place,"], ["e taitasi le mea ma tuu i le mea e tuu ai i le fale o le Atua.", "and place them in the house of God."]]},
  {num:6,words:[["O lenei,", "Now therefore,"], ["Tatenai e,", "Tatnai,"], ["le alii e pule i ona tala atu o le vaitafe;", "governor beyond the river,"], ["Setara-posenai e,", "Shethar-boznai,"], ["ma e pule faatasi ma oulua,", "and your companions the Apharsachites,"], ["o tagata o Afareseka o i ona tala atu o le vaitafe,", "which are beyond the river,"], ["ia taumamao outou ma lena mea;", "be ye far from thence:"]]},
  {num:7,words:[["tuu pea ia le galuega o lena fale o le Atua; ia faia lena fale o le Atua i lona tulafale e le alii e pule i tagata o Iuta,", "Let the work of this house of God alone;"], ["ma toeaina o Iuta.", "let the governor of the Jews and the elders of the Jews build this house of God in his place."]]},
  {num:8,words:[["Ou te fai atu foi i mea tou te faia i toeaina o Iuta e fai ai lena fale o le Atua,", "Moreover I make a decree what ye shall do to the elders of these Jews for the building of this house of God:"], ["ia vave foi ona avatua i na tagata oloa a le tupu,", "that of the king's goods,"], ["o taulaga foi ia i ona tala atu o le vaitafe,", "even of the tribute beyond the river, forthwith expenses be given unto these men,"], ["e totogi ai le galuega ina ia le tuua e i latou le galuega.", "that they be not hindered."]]},
  {num:9,words:[["O mea foi e tatau ia i latou,", "And that which they have need of,"], ["o povi taanoa,", "both young bullocks,"], ["ma mamoe poa,", "and rams,"], ["ma tamai mamoe,", "and lambs,"], ["e fai ma taulaga mu i le Atua o le lagi,", "for the burnt offerings of the God of heaven,"], ["o saito, o masima,", "wheat,"], ["o uaina,", "salt,"], ["ma suauu,", "wine,"], ["e pei ona fai mai ai o faitaulaga o i Ierusalema,", "and oil,"], ["ia tuuina atu ai ia te i latou i lea aso ma lea aso,", "according to the appointment of the priests which are at Jerusalem,"], ["aua ne'i faatamala;", "let it be given them day by day without fail:"]]},
  {num:10,words:[["ina ia latou faitaulaga a'i i mea manogi i le Atua o le lagi,", "That they may offer sacrifices of sweet savours unto the God of heaven, and pray for the life of the king,"], ["ma tatalo ia ola le tupu ma ona atalii.", "and of his sons."]]},
  {num:11,words:[["Ua ou poloai atu foi,", "Also I have made a decree,"], ["ai se tagata na te liua lenei upu,", "that whosoever shall alter this word,"], ["ia toina se laau ai lona fale,", "let timber be pulled down from his house,"], ["ia siitia foi o ia,", "and being set up,"], ["ma ia faamauina i ona luga;", "let him be hanged thereon;"], ["ia fai foi lona fale ma faatafuna ona o lea mea.", "and let his house be made a dunghill for this."]]},
  {num:12,words:[["O le Atua foi o le na faatumauina lona suafa i lea mea, ia lafo i lalo e ia atoa uma tupu ma nuu,", "And the God that hath caused his name to dwell there destroy all kings and people,"], ["o e faaloaloa o latou lima e liliu ma faataumaoi lenei fale o le Atua o i Ierusalema.", "that shall put to their hand to alter and to destroy this house of God which is at Jerusalem."], ["O a'u o Tariu ua ou poloai atu;", "I Darius have made a decree;"], ["ia matuā faia lava.", "let it be done with speed."]]},
  {num:13,words:[["Ona vave faia lea e Tatenai o le alii e pule i ona tala mai o le vaitafe,", "Then Tatnai, governor on this side the river,"], ["o Setara-posenai,", "Shethar-boznai, and their companions,"], ["ma e pule faatasi ma i laua e pei o le feau mai le tupu o Tariu.", "according to that which Darius the king had sent, so they did speedily."]]},
  {num:14,words:[["Ona fai lea e toeaina o Iuta o le fale ,", "And the elders of the Jews builded,"], ["ua manuia foi ona o le perofeta ane a Hakai le perofeta,", "and they prospered through the prophesying of Haggai the prophet and Zechariah the son of Iddo. And they builded,"], ["ma Sakaria le atalii o Ito. Sa latou faia le fale ma faaumaina ai,", "and finished it,"], ["e tusa ma le poloaiga a le Atua o Isaraelu,", "according to the commandment of the God of Israel,"], ["ma le poloaiga a Kuresa,", "and according to the commandment of Cyrus,"], ["ma Tariu,", "and Darius,"], ["ma Aretaseta le tupu o Peresia.", "and Artaxerxes king of Persia."]]},
  {num:15,words:[["Ua faaumaina lenei fale i le aso tolu o le masina o Atara,", "And this house was finished on the third day of the month Adar,"], ["o le ono lea o tausaga o le nofoaiga a le tupu o Tariu.", "which was in the sixth year of the reign of Darius the king."]]},
  {num:16,words:[["Ua faia le faaulufalega o lenei fale o le Atua ma le fiafia e le fanauga a Isaraelu,", "And the children of Israel, the priests,"], ["o faitaulaga,", "and the Levites,"], ["ma sa Levi,", "and the rest of the children of the captivity, kept the dedication of this house of God with joy,"]]},
  {num:17,words:[["ma tagata uma o le tafeaga,", "And offered at the dedication of this house of God an hundred bullocks,"], ["ua latou fai taulaga foi i le faaulufalega o lenei fale o le Atua,", "two hundred rams,"], ["o povi poa e selau, o mamoe poa e lua selau,", "four hundred lambs;"], ["ma tamai mamoe e fa selau;", "and for a sin offering for all Israel,"], ["ma 'oti poa e fai ma taulaga mo le agasala ona o Isaraelu uma e sefulu ma le lua ia,", "twelve he goats,"], ["e tusa ma le faitau o itu aiga o Isaraelu.", "according to the number of the tribes of Israel."]]},
  {num:18,words:[["Ua latou tofia faitaulaga i o latou vasega,", "And they set the priests in their divisions,"], ["ma sa Levi i o latou vasega,", "and the Levites in their courses,"], ["e fai ai le galuega a le Atua o i Ierusalema,", "for the service of God, which is at Jerusalem;"], ["e pei ona tusia i le tusi a Mose.", "as it is written in the book of Moses."]]},
  {num:19,words:[["Ua faia e tagata o le tafeaga le paseka i le aso e sefulu ma le fa o le uluai masina.", "And the children of the captivity kept the passover upon the fourteenth day of the first month."]]},
  {num:20,words:[["Auā sa faamamāina faatasi le au faitaulaga ma sa Levi,", "For the priests and the Levites were purified together,"], ["ua mamā i latou uma,", "all of them were pure,"], ["ua latou fasi foi le paseka mo tagata uma o le tafeaga,", "and killed the passover for all the children of the captivity,"], ["ma o latou uso o le au faitaulaga,", "and for their brethren the priests,"], ["atoa ma i latou lava.", "and for themselves."]]},
  {num:21,words:[["Ua aai ai foi le fanauga a Isaraelu e na foi mai i le tafeaga,", "And the children of Israel, which were come again out of captivity,"], ["ma i latou uma e na vavae mai ia te i latou ai le leaga o tagata ese o i le nuu,", "and all such as had separated themselves unto them from the filthiness of the heathen of the land,"], ["e saili atu ai ia Ieova le Atua o Isaraelu;", "to seek the LORD God of Israel, did eat,"]]},
  {num:22,words:[["ma latou faia le tausamiga o areto e le faafefeteina i aso e fitu ma le fiafia;", "And kept the feast of unleavened bread seven days with joy:"], ["auā sa faafiafiaina i latou e Ieova,", "for the LORD had made them joyful,"], ["na ia liliu foi le loto o le tupu o Asuria ia te i latou e faamalolosi ai o latou lima i le faiga o le fale o le Atua,", "and turned the heart of the king of Assyria unto them, to strengthen their hands in the work of the house of God,"], ["o le Atua o Isaraelu.", "the God of Israel."]]},
];
renderVerseSet(ezr_ch_6_Verses, 'ezr-ch6-verses');

var ezr_ch_7_Verses = [
  {num:1,words:[["E mulimuli ane foi i nei mea,", "Now after these things,"], ["i le nofoaiga Aretaseta le tupu o Peresia,", "in the reign of Artaxerxes king of Persia,"], ["ua alu ae ai Esera le atalii o Seraia,", "Ezra the son of Seraiah,"], ["o le atalii ia o Asaria,", "the son of Azariah,"], ["o le atalii ia o Hilikia,", "the son of Hilkiah,"]]},
  {num:2,words:[["o le atalii ia o Saluma,", "The son of Shallum,"], ["o le atalii ia o Satoka,", "the son of Zadok,"], ["o le atalii ia o Akitopo,", "the son of Ahitub,"]]},
  {num:3,words:[["o le atalii ia o Amaria,", "The son of Amariah,"], ["o le atalii ia o Asaria,", "the son of Azariah,"], ["o le atalii ia o Meraiota,", "the son of Meraioth,"]]},
  {num:4,words:[["o le atalii ia o Serakia,", "The son of Zerahiah,"], ["o le atalii ia o Usi,", "the son of Uzzi,"], ["o le atalii ia o Puki,", "the son of Bukki,"]]},
  {num:5,words:[["o le atalii ia o Apisua,", "The son of Abishua,"], ["o le atalii ia o Fineaso,", "the son of Phinehas,"], ["o le atalii ia o Eleasaro,", "the son of Eleazar,"], ["o le atalii ia o Arona le faitaulaga sili.", "the son of Aaron the chief priest:"]]},
  {num:6,words:[["O Esera lea na alu ae nai Papelonia;", "This Ezra went up from Babylon;"], ["o le tusiupu poto foi o ia i le tulafono a Mose,", "and he was a ready scribe in the law of Moses,"], ["na tuuina mai e Ieova le Atua o Isaraelu;", "which the LORD God of Israel had given:"], ["ua tuuina mai foi e le tupu ia te ia atoa uma mea na ia fai atu ai,", "and the king granted him all his request,"], ["e tusa ma le aao o Ieova lona Atua na ia te ia.", "according to the hand of the LORD his God upon him."]]},
  {num:7,words:[["Ua o ae foi nisi o le fanauga a Isaraelu,", "And there went up some of the children of Israel,"], ["ma nisi o le au faitaulaga,", "and of the priests,"], ["ma sa Levi,", "and the Levites,"], ["ma e pepese,", "and the singers,"], ["ma leoleo faitotoa,", "and the porters,"], ["ma netini,", "and the Nethinims,"], ["i Ierusalema,", "unto Jerusalem,"], ["i le fitu o tausaga o le tupu o Aretaseta.", "in the seventh year of Artaxerxes the king."]]},
  {num:8,words:[["Ua oo foi o ia i Ierusalema i le lima o masina o le fitu o tausaga o le tupu.", "And he came to Jerusalem in the fifth month, which was in the seventh year of the king."]]},
  {num:9,words:[["Auā o le aso muamua o le masina muamua na amata ai ona alu ae o ia nai Papelonia;", "For upon the first day of the first month began he to go up from Babylon,"], ["o le aso muamua foi o le lima o masina na oo atu ai o ia i Ierusalema,", "and on the first day of the fifth month came he to Jerusalem,"], ["e tusa ma le aao alofa o lona Atua ua ia te ia.", "according to the good hand of his God upon him."]]},
  {num:10,words:[["Auā na saunia e Esera lona loto e saili i le tulafono a Ieova ma fai ai,", "For Ezra had prepared his heart to seek the law of the LORD,"], ["ma a'oa'o atu i Isaraelu i le tulafono,", "and to do it,"], ["ma faamasinoga.", "and to teach in Israel statutes and judgments."]]},
  {num:11,words:[["O le ata lenei o le tusi na avatua e le tupu o Aretaseta ia Esera le faitaulaga le tusiupu,", "Now this is the copy of the letter that the king Artaxerxes gave unto Ezra the priest,"], ["o le tusiupu lea i upu o poloaiga a Ieova,", "the scribe, even a scribe of the words of the commandments of the LORD,"], ["ma ana tulafono ia Isaraelu.", "and of his statutes to Israel."]]},
  {num:12,words:[["O Aretaseta le tupu o tupu ia Esera le faitaulaga,", "Artaxerxes,"], ["o le tusiupu o le tulafono a le Atua o le lagi;", "king of kings,"], ["ia atoatoa lou manuia ,", "unto Ezra the priest, a scribe of the law of the God of heaven,"], ["ua faapea,", "perfect peace,"], ["Ou te fai atu,", "and at such a time."]]},
  {num:13,words:[["O i latou uma o le nuu o Isaraelu,", "I make a decree,"], ["ma ona faitaulaga,", "that all they of the people of Israel,"], ["ma sa Levi,", "and of his priests and Levites,"], ["o i lo'u malo,", "in my realm,"], ["o e loto ina o,", "which are minded of their own freewill to go up to Jerusalem,"], ["ia latou o faatasi ma oe i Ierusalema.", "go with thee."]]},
  {num:14,words:[["Ona ua auina oe e le tupu,", "Forasmuch as thou art sent of the king,"], ["ma alii e pule e toafitu ua ia te ia,", "and of his seven counsellors,"], ["e suesue ia Iuta ma Ierusalema,", "to enquire concerning Judah and Jerusalem,"], ["e tusa ma le tulafono a lou Atua ua i ou lima;", "according to the law of thy God which is in thine hand;"]]},
  {num:15,words:[["e te avatua foi le ario ma le auro ua foai ma le loto e le tupu,", "And to carry the silver and gold,"], ["ma alii e pule ua ia te ia,", "which the king and his counsellors have freely offered unto the God of Israel,"], ["i le Atua o Isaraelu o le ua i ai i Ierusalema lona malumalu,", "whose habitation is in Jerusalem,"]]},
  {num:16,words:[["atoa ma le ario uma ma le auro e te maua i le itu malo uma o Papelonia,", "And all the silver and gold that thou canst find in all the province of Babylon,"], ["ma mea ua foai ma le loto e le nuu,", "with the freewill offering of the people,"], ["ma faitaulaga,", "and of the priests,"], ["o foai ma le loto mo le fale o lo latou Atua o i Ierusalema;", "offering willingly for the house of their God which is in Jerusalem:"]]},
  {num:17,words:[["ina ia matua faatau i nei tupe,", "That thou mayest buy speedily with this money bullocks,"], ["o povi poa, o mamoe poa,", "rams,"], ["o tamai mamoe,", "lambs,"], ["ma o latou taulaga i mea e 'ai, ma o latou taulaga i mea e inu,", "with their meat offerings and their drink offerings,"], ["ma fai taulaga a'i i le fata faitaulaga o i le fale o lo outou Atua o i Ierusalema.", "and offer them upon the altar of the house of your God which is in Jerusalem."]]},
  {num:18,words:[["O le mea foi e lelei ia te oe ma ou uso e fai i toe o ario ma auro,", "And whatsoever shall seem good to thee, and to thy brethren,"], ["ia faia lea e tusa ma le finagalo o lo outou Atua.", "to do with the rest of the silver and the gold, that do after the will of your God."]]},
  {num:19,words:[["O ipu foi ua avatua ia te oe e auauna a'i i le fale o lou Atua,", "The vessels also that are given thee for the service of the house of thy God,"], ["ia e tuuina atu ai i luma o le Atua o Ierusalema.", "those deliver thou before the God of Jerusalem."]]},
  {num:20,words:[["O isi mea foi e aoga i le fale o lou Atua,", "And whatsoever more shall be needful for the house of thy God,"], ["e te manatu i ai e avatu,", "which thou shalt have occasion to bestow,"], ["ia avatua nai le fale oloa o le tupu.", "bestow it out of the king's treasure house."]]},
  {num:21,words:[["O a'u foi,", "And I,"], ["o a'u le tupu o Aretaseta,", "even I Artaxerxes the king, do make a decree to all the treasurers which are beyond the river,"], ["ua ou poloai atu i tausi oloa uma o i ona tala atu o le vaitafe,", "that whatsoever Ezra the priest,"], ["ia matua faia mea uma e fai atu ai ia te outou e Esera le faitaulaga,", "the scribe of the law of the God of heaven, shall require of you,"], ["o le tusiupu o le tulafono a le Atua o le lagi,", "it be done speedily,"]]},
  {num:22,words:[["e oo i le selau o taleni o ario,", "Unto an hundred talents of silver,"], ["e oo foi i le selau o kori o saito,", "and to an hundred measures of wheat,"], ["e oo foi i le selau o paita o uaina,", "and to an hundred baths of wine,"], ["e oo foi i le selau o paita o suāuu,", "and to an hundred baths of oil,"], ["ma masima ua le tusia sona fua .", "and salt without prescribing how much."]]},
  {num:23,words:[["O mea uma ua poloai mai ai e le Atua o le lagi,", "Whatsoever is commanded by the God of heaven,"], ["ia matua faia mo le fale o le Atua o le lagi;", "let it be diligently done for the house of the God of heaven:"], ["auā se a ea le mea e oo ai le toasa i le malo o le tupu ma ona atalii?", "for why should there be wrath against the realm of the king and his sons?"]]},
  {num:24,words:[["Ua matou faailoa atu foi ia te outou ia le au faitaulaga uma,", "Also we certify you,"], ["ma sa Levi,", "that touching any of the priests and Levites,"], ["o le au pepese,", "singers,"], ["o le au leoleo faitotoa,", "porters,"], ["o le au netini,", "Nethinims, or ministers of this house of God,"], ["ma le au faigaluega i lena fale o le Atua,", "it shall not be lawful to impose toll,"], ["aua ne'i totogi atu ia te i latou ia faia taulaga,", "tribute,"], ["ma taulaga i mea eseese,", "or custom,"], ["ma taulaga o ala.", "upon them."]]},
  {num:25,words:[["O oe foi Esera e,", "And thou,"], ["ia e tofia,", "Ezra,"], ["e tusa ma le poto o lou Atua o ia te oe,", "after the wisdom of thy God,"], ["o faamasino ma faatonu,", "that is in thine hand,"], ["latou te faatonuina atu i le nuu uma o i ona tala atu o le vaitafe,", "set magistrates and judges,"], ["o i latou uma o e iloa le tulafono a lou Atua;", "which may judge all the people that are beyond the river,"], ["o i latou foi o e le iloa,", "all such as know the laws of thy God;"], ["ia e a'oa'o atu ia te i latou.", "and teach ye them that know them not."]]},
  {num:26,words:[["Ai so latou na te le faia le tulafono a lou Atua,", "And whosoever will not do the law of thy God,"], ["ma le tulafono a le tupu,", "and the law of the king,"], ["ia matuā faasalaina o ia,", "let judgment be executed speedily upon him,"], ["po o le oti,", "whether it be unto death,"], ["po o le tafia,", "or to banishment,"], ["po o se totogi ia faia,", "or to confiscation of goods,"], ["pe ia noanoatia.", "or to imprisonment."]]},
  {num:27,words:[["Ia faafetaia Ieova le Atua o tatou tamā,", "Blessed be the LORD God of our fathers,"], ["o le na tuuina mai lenei mea i le finagalo o le tupu,", "which hath put such a thing as this in the king's heart,"], ["e faamatagofie ai le fale o Ieova o i Ierusalema;", "to beautify the house of the LORD which is in Jerusalem:"]]},
  {num:28,words:[["ma na faaoo mai le alofa ia te au i luma o le tupu,", "And hath extended mercy unto me before the king,"], ["ma ana faipule,", "and his counsellors,"], ["ma luma foi o alii fitafita uma o le tupu. Na faamalosia foi a'u e tusa ma le aao o Ieova lo'u Atua na ia te au,", "and before all the king's mighty princes. And I was strengthened as the hand of the LORD my God was upon me,"], ["ua ou faapotopotoina foi mai ia Isaraelu o alii matou te o ae ma a'u.", "and I gathered together out of Israel chief men to go up with me."]]},
];
renderVerseSet(ezr_ch_7_Verses, 'ezr-ch7-verses');

var ezr_ch_8_Verses = [
  {num:1,words:[["O i latou nei o matai sili,", "These are now the chief of their fathers, and this is the genealogy of them that went up with me from Babylon,"], ["ma le tusi gafa o i latou e na o ae faatasi ma a'u ai Papelonia i le nofoaiga a le tupu o Aretaseta.", "in the reign of Artaxerxes the king."]]},
  {num:2,words:[["O lo le fanauga a Fineaso,", "Of the sons of Phinehas;"], ["o Keresona;", "Gershom:"], ["o lo le fanauga a Itamaro,", "of the sons of Ithamar;"], ["o Tanielu;", "Daniel:"], ["o lo le fanauga a Tavita,", "of the sons of David;"], ["o Hatusa.", "Hattush."]]},
  {num:3,words:[["O lo le fanauga a Sakania,", "Of the sons of Shechaniah,"], ["o lo le fanauga a Parose,", "of the sons of Pharosh;"], ["o Sakaria;", "Zechariah:"], ["ma ua ia te ia e ua tusigafaina o tane e toaselau ma le toalimagafulu.", "and with him were reckoned by genealogy of the males an hundred and fifty."]]},
  {num:4,words:[["O lo le fanauga a Paka-moapi,", "Of the sons of Pahath-moab;"], ["o Elioenai le atalii o Serakia,", "Elihoenai the son of Zerahiah,"], ["ma ua ia te ia o tane e toalua lau.", "and with him two hundred males."]]},
  {num:5,words:[["O lo le fanauga a Sekania;", "Of the sons of Shechaniah;"], ["o le atalii o Iaaseelu,", "the son of Jahaziel,"], ["ma ua ia te ia o tane e toatolu selau.", "and with him three hundred males."]]},
  {num:6,words:[["O lo le fanauga a Atini,", "Of the sons also of Adin;"], ["o Epete le atalii o Ionatana,", "Ebed the son of Jonathan,"], ["ma ua ia te ia o tane e toalimagafulu.", "and with him fifty males."]]},
  {num:7,words:[["O lo le fanauga a Elama,", "And of the sons of Elam;"], ["o Isaia le atalii o Atalia,", "Jeshaiah the son of Athaliah,"], ["ma ua ia te ia o tane e toafitugafulu.", "and with him seventy males."]]},
  {num:8,words:[["O lo le fanauga a Sefatia,", "And of the sons of Shephatiah;"], ["o Sepatia le atalii o Mekaeli,", "Zebadiah the son of Michael,"], ["ma ua ia te ia o tane e toavalugafulu.", "and with him fourscore males."]]},
  {num:9,words:[["O lo le fanauga a Ioapo,", "Of the sons of Joab;"], ["o Opetaia le atalii o Ikieli,", "Obadiah the son of Jehiel,"], ["ma ua ia te ia o tane e toalua lau ma le toatinoagafulu ma le toavalu.", "and with him two hundred and eighteen males."]]},
  {num:10,words:[["O lo le fanauga a Salome,", "And of the sons of Shelomith;"], ["o le atalii o Iosefia, ma ua ia te ia o tane e toaselau ma le toaonogafulu. O lo le fanauga a Pepai,", "the son of Josiphiah,"], ["o Sakaria le atalii o Pekai,", "and with him an hundred and threescore males."]]},
  {num:11,words:[["ma ua ia te ia o tane e toaluafulu ma le toavalu.", "And of the sons of Bebai; Zechariah the son of Bebai, and with him twenty and eight males."]]},
  {num:12,words:[["O lo le fanauga a Asegata,", "And of the sons of Azgad;"], ["o Iokana le atalii o Hakatana,", "Johanan the son of Hakkatan,"], ["ma ua ia te ia o tane e toaselau ma le toasefulu.", "and with him an hundred and ten males."]]},
  {num:13,words:[["O le fanauga a Atonikama,", "And of the last sons of Adonikam,"], ["o e na mulimuli,", "whose names are these,"], ["o latou igoa foi nei, o Elipelete,", "Eliphelet,"], ["o Ieielu,", "Jeiel,"], ["ma Semaia,", "and Shemaiah,"], ["ma ua ia te i latou o tane e toaonogafulu.", "and with them threescore males."]]},
  {num:14,words:[["O le fanauga a Pikevai;", "Of the sons also of Bigvai;"], ["o Utai ma Saputo,", "Uthai, and Zabbud,"], ["ma ua ia te i laua o tane e toafitugafulu.", "and with them seventy males."]]},
  {num:15,words:[["Ua ou faapotopotoina i latou i le vaitafe ua tafe atu i Aava;", "And I gathered them together to the river that runneth to Ahava;"], ["ona nonofo lea o i matou i lea mea i aso e tolu;", "and there abode we in tents three days:"], ["ua ou suesue foi i le nuu ma le au faitaulaga,", "and I viewed the people, and the priests,"], ["a e lei maua i lea mea ni o le fanauga a Levi.", "and found there none of the sons of Levi."]]},
  {num:16,words:[["Ona ou aamiatua lea o Elisara,", "Then sent I for Eliezer,"], ["ma Arielu,", "for Ariel,"], ["ma Semaia,", "for Shemaiah,"], ["ma Elenatana,", "and for Elnathan,"], ["ma Iaripa,", "and for Jarib,"], ["ma Elenatana,", "and for Elnathan,"], ["ma Natano,", "and for Nathan,"], ["ma Sakaria,", "and for Zechariah,"], ["ma Mesulama,", "and for Meshullam,"], ["o alii i latou;", "chief men;"], ["atoa ma Iaripa,", "also for Joiarib,"], ["ma Elenatano,", "and for Elnathan,"], ["o tagata popoto i laua.", "men of understanding."]]},
  {num:17,words:[["Ua ou aauina atu i latou ia Itu le alii i le nuu o Kasipeia,", "And I sent them with commandment unto Iddo the chief at the place Casiphia,"], ["ua ou tuuina atu foi ia te i latou o upu latou te fai atu ai ia Itu,", "and I told them what they should say unto Iddo,"], ["ma ona uso le au netini,", "and to his brethren the Nethinims,"], ["na i le nuu o Kasipeia,", "at the place Casiphia,"], ["ia latou tuuina mai ia te i matou ni e auauna i le fale o lo matou Atua.", "that they should bring unto us ministers for the house of our God."]]},
  {num:18,words:[["Ona latou tuuina mai lea ia te i matou,", "And by the good hand of our God upon us they brought us a man of understanding,"], ["e tusa ma le aao alofa o lo matou Atua na ia te i matou,", "of the sons of Mahli,"], ["o le tagata faautauta o lo le fanauga a Maali le atalii o Levi,", "the son of Levi,"], ["o le atalii ia o Isaraelu; ma Serepeia,", "the son of Israel;"], ["ma ona atalii,", "and Sherebiah,"], ["ma ona uso,", "with his sons and his brethren,"], ["e toatinoagafulu ma le toavalu;", "eighteen;"]]},
  {num:19,words:[["ma Hasapea,", "And Hashabiah,"], ["ma ua ia te ia Isaia o lo le fanauga a Merari,", "and with him Jeshaiah of the sons of Merari, his brethren and their sons,"], ["o ona uso ma o latou atalii e toaluafulu;", "twenty;"]]},
  {num:20,words:[["ma nisi o le au netini e na tofia e Tavita ma alii i le galuega a sa Levi,", "Also of the Nethinims,"], ["o netini e toalua lau ma le toaluafulu,", "whom David and the princes had appointed for the service of the Levites, two hundred and twenty Nethinims:"], ["na ta'ua i latou uma i o latou igoa.", "all of them were expressed by name."]]},
  {num:21,words:[["Ona ou tala'iina lea o le anapogi i lea mea i le vaitafe o Aava,", "Then I proclaimed a fast there,"], ["ia faatigaina i matou e i matou i luma o lo matou Atua,", "at the river of Ahava,"], ["e saili mai ia te ia se ala tonu mo matou,", "that we might afflict ourselves before our God, to seek of him a right way for us,"], ["ma o matou tama iti,", "and for our little ones,"], ["ma a matou mea uma.", "and for all our substance."]]},
  {num:22,words:[["Auā na ou mā i faatoga i le tupu i se 'au ma ni e tietie i solofanua e fesoasoani ia i matou i e saua mai i le ala;", "For I was ashamed to require of the king a band of soldiers and horsemen to help us against the enemy in the way:"], ["auā na matou fai atu i le tupu,", "because we had spoken unto the king,"], ["ua faapea,", "saying,"], ["O le aao o lo matou Atua ua i luga ia te i latou uma o e sailiili atu ia te ia e lelei ai i latou;", "The hand of our God is upon all them for good that seek him;"], ["a o lona mamana ma lona toasa ua i luga ia te i latou uma o e tuua o ia.", "but his power and his wrath is against all them that forsake him."]]},
  {num:23,words:[["Ua matou anapopogi foi ma sailiili i lo matou Atua ona o lea mea,", "So we fasted and besought our God for this:"], ["ma ua faafofoga mai ai o ia ia te i matou.", "and he was intreated of us."]]},
  {num:24,words:[["Ona ou vavaeeseina lea ni alii o le au faitaulaga e toasefulu ma le toalua,", "Then I separated twelve of the chief of the priests,"], ["o Serepeia,", "Sherebiah,"], ["ma Hasapea,", "Hashabiah,"], ["ma ua ia te i laua ni o latou uso e toatinoagafulu.", "and ten of their brethren with them,"]]},
  {num:25,words:[["Ona ou fuatia lea ia te i latou o le ario,", "And weighed unto them the silver,"], ["ma le auro,", "and the gold, and the vessels,"], ["ma ipu,", "even the offering of the house of our God,"], ["o taulaga i le fale o lo matou Atua na faia e le tupu,", "which the king,"], ["ma ana faipule,", "and his counsellors,"], ["ma alii ua ia te ia,", "and his lords, and all Israel there present,"], ["ma Isaraelu uma e na i ai i lea mea;", "had offered:"]]},
  {num:26,words:[["na ou fuatia i o latou lima o taleni o ario e ono selau ma le limagafulu,", "I even weighed unto their hand six hundred and fifty talents of silver,"], ["ma taleni e selau o ipu ario,", "and silver vessels an hundred talents,"], ["ma taleni o auro e selau;", "and of gold an hundred talents;"]]},
  {num:27,words:[["o ipu auro foi e luafulu,", "Also twenty basons of gold,"], ["e afe o tareki ia;", "of a thousand drams; and two vessels of fine copper,"], ["ma ipu 'apa memea pupula e lelei e lua e tāua e tusa ma auro.", "precious as gold."]]},
  {num:28,words:[["Ona ou fai atu lea ia te i latou,", "And I said unto them,"], ["Ua paia outou mo Ieova;", "Ye are holy unto the LORD;"], ["ua paia foi ipu;", "the vessels are holy also;"], ["o le ario foi ma le auro o le taulaga lea ua fai ma le loto ia Ieova le Atua o outou tamā;", "and the silver and the gold are a freewill offering unto the LORD God of your fathers."]]},
  {num:29,words:[["ia outou mataala,", "Watch ye,"], ["ma tausi i ai seia outou fuaina atu ai i luma o alii o le au faitaulaga,", "and keep them,"], ["ma sa Levi,", "until ye weigh them before the chief of the priests and the Levites,"], ["ma matai sili o Isaraelu,", "and chief of the fathers of Israel,"], ["i Ierusalema,", "at Jerusalem,"], ["i potu o le fale o Ieova.", "in the chambers of the house of the LORD."]]},
  {num:30,words:[["Ona talia lea e le au faitaulaga ma sa Levi o le fua o le ario,", "So took the priests and the Levites the weight of the silver,"], ["ma le auro,", "and the gold,"], ["ma ipu,", "and the vessels,"], ["e faaoo ai i Ierusalema i le fale o lo matou Atua.", "to bring them to Jerusalem unto the house of our God."]]},
  {num:31,words:[["Ona matou o ai lea nai le vaitafe o Aava i le aso e sefulu ma le lua o le masina muamua,", "Then we departed from the river of Ahava on the twelfth day of the first month,"], ["o le a o i Ierusalema;", "to go unto Jerusalem:"], ["na i ai le aao o lo matou Atua i luga ia te i matou,", "and the hand of our God was upon us,"], ["ma ua ia laveaiina i matou ai lima o e saua,", "and he delivered us from the hand of the enemy,"], ["ma e lamalama mai i le ala.", "and of such as lay in wait by the way."]]},
  {num:32,words:[["Ua matou oo foi i Ierusalema,", "And we came to Jerusalem,"], ["ma nonofo ai i aso e tolu.", "and abode there three days."]]},
  {num:33,words:[["O le fa o aso foi na fuaina ai le ario,", "Now on the fourth day was the silver and the gold and the vessels weighed in the house of our God by the hand of Meremoth the son of Uriah the priest;"], ["ma le auro, ma ipu,", "and with him was Eleazar the son of Phinehas;"], ["i le fale o lo matou Atua i le lima o Meremota le atalii o Uria le faitaulaga,", "and with them was Jozabad the son of Jeshua,"], ["ua ia te ia foi Eleasaro le atalii o Fineaso; ua faatasi foi ma i laua o Iosapata le atalii o Iosua,", "and Noadiah the son of Binnui,"], ["ma Noateia le atalii o Pinui o sa Levi i laua.", "Levites;"]]},
  {num:34,words:[["Ua faitauina ma fuatia ia mea uma,", "By number and by weight of every one:"], ["ma ua tusia le fua o ia mea uma i lea lava aso.", "and all the weight was written at that time."]]},
  {num:35,words:[["O e na o mai mai le tafeaga,", "Also the children of those that had been carried away,"], ["o tagata na aunuua,", "which were come out of the captivity,"], ["na latou osia taulaga mu i le Atua o Isaraelu,", "offered burnt offerings unto the God of Israel,"], ["o povi poa e sefulu ma le lua mo Isaraelu uma,", "twelve bullocks for all Israel,"], ["ma mamoe poa e ivagafulu ma le ono,", "ninety and six rams,"], ["ma tamai mamoe e fitugafulu ma le fitu,", "seventy and seven lambs,"], ["ma 'oti poa e sefulu ma le lua,", "twelve he goats for a sin offering:"], ["o le taulaga mo le agasala o ia mea uma o taulaga mu ia Ieova.", "all this was a burnt offering unto the LORD."]]},
  {num:36,words:[["Ua latou tuuina atu foi le poloaiga a le tupu i alii sili na tofia e le tupu,", "And they delivered the king's commissions unto the king's lieutenants,"], ["ma alii e pule i ona tala mai o le vaitafe,", "and to the governors on this side the river:"], ["ona latou fesoasoani lea i le nuu,", "and they furthered the people,"], ["ma le fale o le Atua.", "and the house of God."]]},
];
renderVerseSet(ezr_ch_8_Verses, 'ezr-ch8-verses');

var ezr_ch_9_Verses = [
  {num:1,words:[["Ua uma nei mea,", "Now when these things were done,"], ["ona o mai lea ia te au o alii,", "the princes came to me,"], ["ua faapea mai,", "saying,"], ["O le nuu o Isaraelu,", "The people of Israel,"], ["ma le au faitaulaga,", "and the priests,"], ["ma sa Levi,", "and the Levites,"], ["ua latou le vavaeina i latou ai tagata o nuu ese,", "have not separated themselves from the people of the lands,"], ["a o loo fai e tusa ma a latou mea e inosia,", "doing according to their abominations,"], ["o sa Kananā,", "even of the Canaanites,"], ["o sa Heti,", "the Hittites,"], ["o sa Perisē,", "the Perizzites,"], ["o sa Iepusē,", "the Jebusites,"], ["o sa Amoni,", "the Ammonites,"], ["o sa Moapi,", "the Moabites,"], ["o tagata Aikupito,", "the Egyptians,"], ["ma sa Amori.", "and the Amorites."]]},
  {num:2,words:[["Auā ua latou fai avā i o latou afafine,", "For they have taken of their daughters for themselves,"], ["o i latou atoa ma o latou atalii,", "and for their sons:"], ["ma ua fefiloi le fanau paia ma tagata o ia nuu,", "so that the holy seed have mingled themselves with the people of those lands: yea,"], ["ma ua solomua alii ma faipule i lenei agasala.", "the hand of the princes and rulers hath been chief in this trespass."]]},
  {num:3,words:[["Ua ou faalogo i lenei mea,", "And when I heard this thing,"], ["ona ou saeia lea o lo'u ofu ma lo'u ofu talaloa,", "I rent my garment and my mantle,"], ["ma ou futi o'u lauulu, ma la'u 'ava,", "and plucked off the hair of my head and of my beard,"], ["ma ou nofo i lalo ua segia lo'u mauli.", "and sat down astonied."]]},
  {num:4,words:[["Ona potopoto mai ai lea ia te au o i latou uma na matatau i afioga a le Atua o Isaraelu,", "Then were assembled unto me every one that trembled at the words of the God of Israel,"], ["ona o le agasala a le tafeaga; ua ou nofo foi ua segia lo'u mauli,", "because of the transgression of those that had been carried away;"], ["ua oo i le taulaga o le afiafi.", "and I sat astonied until the evening sacrifice."]]},
  {num:5,words:[["Ua oo i le taulaga o le afiafi, ona ou tulai lea ai lo'u tiga,", "And at the evening sacrifice I arose up from my heaviness;"], ["ua saeia lo'u ofu,", "and having rent my garment and my mantle,"], ["ma lo'u ofu talaloa,", "I fell upon my knees,"], ["ma ua ou tootuli i o'u tulivae, ma faaloaloa atu o'u lima ia Ieova lo'u Atua,", "and spread out my hands unto the LORD my God,"]]},
  {num:6,words:[["ma ou faapea atu,", "And said,"], ["Lo'u Atua e,", "O my God,"], ["ua ou mā, ma ou masiasi i tepa ae o'u mata ia te oe,", "I am ashamed and blush to lift up my face to thee,"], ["lo'u Atua e;", "my God:"], ["auā ua tele lo matou leaga ua oo i luga o matou ulu,", "for our iniquities are increased over our head,"], ["ma ua tupu tele la matou agasala ua oo lava i le lagi.", "and our trespass is grown up unto the heavens."]]},
  {num:7,words:[["Talu ona po o matou tama ua ia i matou le agasala tele ua oo i le aso nei;", "Since the days of our fathers have we been in a great trespass unto this day;"], ["ona o lo matou leaga foi ua tuuina ai matou,", "and for our iniquities have we,"], ["o matou tupu,", "our kings,"], ["ma a matou faitaulaga,", "and our priests,"], ["i lima o tupu o ia nuu,", "been delivered into the hand of the kings of the lands,"], ["i le pelu,", "to the sword,"], ["ia tafia,", "to captivity,"], ["ma ia vetea,", "and to a spoil,"], ["ma ia masiasi,", "and to confusion of face,"], ["e pei ona fai i le aso nei.", "as it is this day."]]},
  {num:8,words:[["A o nei ona po,", "And now for a little space grace hath been shewed from the LORD our God,"], ["e pei o se emo itiiti, ua ia te i matou le alofa mai ia Ieova lo matou Atua,", "to leave us a remnant to escape,"], ["ina ia faatoeina ia te i matou o e ua sao,", "and to give us a nail in his holy place,"], ["ma ia tuuina mai ia te i matou se fao i lana mea paia, e faamalamalamaina ai o matou mata e lo matou Atua,", "that our God may lighten our eyes,"], ["e tuuina mai ai foi se olataga itiiti ina o fai i matou ma pologa.", "and give us a little reviving in our bondage."]]},
  {num:9,words:[["Auā o pologa i matou,", "For we were bondmen;"], ["a ua le tiaiina i matou e lo matou Atua ina o fai i matou ma pologa,", "yet our God hath not forsaken us in our bondage,"], ["a ua ia faaoo ia te i matou le alofa i luma o tupu o Peresia,", "but hath extended mercy unto us in the sight of the kings of Persia,"], ["ia tuuina mai ia te i matou le olataga,", "to give us a reviving,"], ["ia faatuina le fale o lo matou Atua,", "to set up the house of our God,"], ["ma ia teuteuina mea o i ai ua lepetia,", "and to repair the desolations thereof,"], ["ma ia tuuina mai ia te i matou le pa i Iuta ma Ierusalema.", "and to give us a wall in Judah and in Jerusalem."]]},
  {num:10,words:[["O lenei,", "And now,"], ["lo matou Atua e,", "O our God,"], ["se a ea la matou e fai atu ai ina ua e faia na mea? Auā ua tuua e i matou au poloaiga,", "what shall we say after this? for we have forsaken thy commandments,"]]},
  {num:11,words:[["na e poloai mai ai i au auauna le au perofeta,", "Which thou hast commanded by thy servants the prophets, saying,"], ["ua faapea mai,", "The land, unto which ye go to possess it,"], ["O le nuu tou te o i ai e fai mo outou o le nuu lea ua leaga i le leaga o tagata o ia nuu,", "is an unclean land with the filthiness of the people of the lands,"], ["i a latou mea e inosia ua tutumu ai i lea itu ma lea itu i lo latou leaga.", "with their abominations, which have filled it from one end to another with their uncleanness."]]},
  {num:12,words:[["O lenei,", "Now therefore give not your daughters unto their sons,"], ["aua tou te avatua o outou afafine i o latou atalii,", "neither take their daughters unto your sons,"], ["aua foi tou te aumaia o latou afafine ma o outou atalii, aua foi tou te sailia e faavavau se mea e filemu ai i latou pe manuia ai i latou;", "nor seek their peace or their wealth for ever:"], ["ina ia malolosi ai outou,", "that ye may be strong,"], ["ma ia outou aai ai i mea lelei o i le laueleele,", "and eat the good of the land,"], ["ma fai ai mo outou atalii e faavavau.", "and leave it for an inheritance to your children for ever."]]},
  {num:13,words:[["Ua uma ona oo mai o nei mea uma ia te i matou ona o a matou amio leaga, ma la matou agasala tele,", "And after all that is come upon us for our evil deeds,"], ["auā o oe lo matou Atua e,", "and for our great trespass,"], ["ua e laveai mai,", "seeing that thou our God hast punished us less than our iniquities deserve,"], ["ua le faia e tusa ma lo matou leaga, ma ua e faasaoina i matou faapenei;", "and hast given us such deliverance as this;"]]},
  {num:14,words:[["a toe solia e i matou au poloaiga,", "Should we again break thy commandments,"], ["ma feavāgai ma tagata e fai ia mea e inosia, e te le toasa mai ai ea ia te i matou seia faaumatia i matou ,", "and join in affinity with the people of these abominations? wouldest not thou be angry with us till thou hadst consumed us,"], ["ina ia leai ni e totoe pe faasaoina?", "so that there should be no remnant nor escaping?"]]},
  {num:15,words:[["Ieova e,", "O LORD God of Israel,"], ["le Atua o Isaraelu, o oe o le amiotonu;", "thou art righteous:"], ["auā ua faatotoeina i matou,", "for we remain yet escaped,"], ["ua faasaoina,", "as it is this day:"], ["e pei ona fai i le aso nei;", "behold,"], ["faauta, o i ou luma i matou ma a matou agasala;", "we are before thee in our trespasses:"], ["auā e le mafai ona tutu i matou i ou luma ona o lenei mea.", "for we cannot stand before thee because of this."]]},
];
renderVerseSet(ezr_ch_9_Verses, 'ezr-ch9-verses');

var ezr_ch_10_Verses = [
  {num:1,words:[["A o talotalo Esera,", "Now when Ezra had prayed,"], ["ma ta'uta'u atu a latou agasala , o loo tagi,", "and when he had confessed,"], ["ma faapaū i luma o le fale o le Atua,", "weeping and casting himself down before the house of God,"], ["ua faapotopoto mai ia te ia mai ia Isaraelu o le faapotopotoga tele lava, o tane ma fafine ma tama iti;", "there assembled unto him out of Israel a very great congregation of men and women and children:"], ["auā sa fetagisi le nuu i le tagi tele.", "for the people wept very sore."]]},
  {num:2,words:[["Ona tali mai lea o Sekania le atalii o Ieielu o lo le fanauga a Elama,", "And Shechaniah the son of Jehiel,"], ["ua faapea mai ia Esera,", "one of the sons of Elam,"], ["Ua agasala i matou i lo matou Atua,", "answered and said unto Ezra,"], ["ina ua matou fai avā i fafine ese mai tagata o le nuu;", "We have trespassed against our God,"], ["a o lenei,", "and have taken strange wives of the people of the land:"], ["ua i ai se faatuatuaga mo Isaraelu i lenei mea.", "yet now there is hope in Israel concerning this thing."]]},
  {num:3,words:[["O lenei,", "Now therefore let us make a covenant with our God to put away all the wives,"], ["ia tatou osia le feagaiga ma lo tatou Atua, ia tatou aauina atu o avā uma,", "and such as are born of them,"], ["ma e ua fananau mai ia te i latou,", "according to the counsel of my lord,"], ["e tusa ma le pule a oe lo'u alii, ma e ua matatau i poloaiga a lo tatou Atua;", "and of those that tremble at the commandment of our God;"], ["ma ia faia e tusa ma le tulafono.", "and let it be done according to the law."]]},
  {num:4,words:[["Ina tulai ia,", "Arise;"], ["auā ua ia te oe lenei mea;", "for this matter belongeth unto thee:"], ["matou te faatasi foi ma oe;", "we also will be with thee:"], ["ia e faamalosi,", "be of good courage,"], ["ma ia e faia.", "and do it."]]},
  {num:5,words:[["Ona tulai ai lea o Esera,", "Then arose Ezra,"], ["ma fai atu ia tauto alii o le au faitaulaga,", "and made the chief priests,"], ["ma sa Levi,", "the Levites, and all Israel,"], ["ma Isaraelu uma ia faia e tusa ma lenei upu.", "to swear that they should do according to this word."], ["Ona latou tauto ai lea.", "And they sware."]]},
  {num:6,words:[["Ona tulai lea o Esera ai luma o le fale o le Atua,", "Then Ezra rose up from before the house of God,"], ["ma ua alu atu i le potu o Ioanana le atalii o Eliasipa,", "and went into the chamber of Johanan the son of Eliashib:"], ["ua oo foi o ia i ai,", "and when he came thither,"], ["ua ia le 'ai se areto,", "he did eat no bread,"], ["ua le inu foi se vai,", "nor drink water:"], ["auā sa faanoanoa ona o le agasala a le tafeaga.", "for he mourned because of the transgression of them that had been carried away."]]},
  {num:7,words:[["Ona latou tala'i lea o le upu i Iuta ma Ierusalema, i tagata uma o le tafeaga,", "And they made proclamation throughout Judah and Jerusalem unto all the children of the captivity,"], ["ia potopoto mai i Ierusalema;", "that they should gather themselves together unto Jerusalem;"]]},
  {num:8,words:[["o i latou uma foi e le o mai i e luā,", "And that whosoever would not come within three days,"], ["e tusa ma le pule a alii ma toeaina,", "according to the counsel of the princes and the elders,"], ["e faatoina ane oloa uma,", "all his substance should be forfeited,"], ["ma vavaeeseina o ia ai le faapotopotoga o le tafeaga.", "and himself separated from the congregation of those that had been carried away."]]},
  {num:9,words:[["Ona faapotopoto mai ai lea o tagata uma o Iuta ma Peniamina i Ierusalema i le aso tolu. O le iva lea o masina,", "Then all the men of Judah and Benjamin gathered themselves together unto Jerusalem within three days. It was the ninth month,"], ["o le aso e luafulu o le masina;", "on the twentieth day of the month;"], ["sa nonofo le nuu uma i le malae i luma o le fale o le Atua,", "and all the people sat in the street of the house of God,"], ["ua tetemu ona o lena mea,", "trembling because of this matter,"], ["atoa ma uaga.", "and for the great rain."]]},
  {num:10,words:[["Ona tulai lea o Esera le faitaulaga,", "And Ezra the priest stood up,"], ["ua faapea atu ia te i latou,", "and said unto them,"], ["O outou na ua agasala outou,", "Ye have transgressed, and have taken strange wives,"], ["ina ua outou fai avā i fafine ese e faaopoopo ai i le agasala a Isaraelu.", "to increase the trespass of Israel."]]},
  {num:11,words:[["O lenei,", "Now therefore make confession unto the LORD God of your fathers,"], ["ia outou ta'uta'u atu a outou agasala ia Ieova le Atua o outou tama,", "and do his pleasure:"], ["ma ia outou faia lona finagalo, ma ia outou vavae ese i tagata o le nuu,", "and separate yourselves from the people of the land,"], ["ma fafine ese.", "and from the strange wives."]]},
  {num:12,words:[["Ona tali mai lea o le faapotopotoga uma,", "Then all the congregation answered and said with a loud voice,"], ["ua latou faapea mai ma le leo tele, E pei ona e fetalai mai ia te i matou,", "As thou hast said,"], ["e faapea ona matou faia.", "so must we do."]]},
  {num:13,words:[["A ua toatele le nuu,", "But the people are many,"], ["ma ua tele uaga i ona po nei,", "and it is a time of much rain,"], ["ma ua le lavā ai i matou ona tutū i fafo; e le mafai foi lenei mea i le aso e tasi,", "and we are not able to stand without,"], ["po o aso e lua;", "neither is this a work of one day or two:"], ["auā ua toatele i matou ua soli tulafono i lenei mea;", "for we are many that have transgressed in this thing."]]},
  {num:14,words:[["ia tofia o matou alii o le faapotopotoga uma,", "Let now our rulers of all the congregation stand,"], ["o i latou uma foi o i a matou aai o e ua fai avā i fafine ese,", "and let all them which have taken strange wives in our cities come at appointed times,"], ["ia o mai i latou i ona po a tuu, ma ia faatasi mai ma i latou o toeaina o lea aai ma lea aai,", "and with them the elders of every city,"], ["atoa ma faamasino o i ai,", "and the judges thereof,"], ["seia liliu ese ai ia te i matou le toasa tele o lo matou Atua ona o lenei mea.", "until the fierce wrath of our God for this matter be turned from us."]]},
  {num:15,words:[["Na tofia i lenei mea na o Ionatana le atalii o Asaelu, ma Iekasia le atalii o Tikeva;", "Only Jonathan the son of Asahel and Jahaziah the son of Tikvah were employed about this matter:"], ["o Mesulama foi ma Sapetai le sa Levi ua fesoasoani ia te i laua.", "and Meshullam and Shabbethai the Levite helped them."]]},
  {num:16,words:[["Ua faia faapea foi e tagata o le tafeaga.", "And the children of the captivity did so."], ["Sa vavaeeseina o Esera le faitaulaga,", "And Ezra the priest, with certain chief of the fathers,"], ["ma matai sili e tusa ma aiga o latou tamā,", "after the house of their fathers,"], ["o i latou uma foi ua ta'ua o latou igoa,", "and all of them by their names,"], ["ua latou nonofo i lalo foi i le aso muamua o le masina ae sefulu e suesue i lena mea.", "were separated, and sat down in the first day of the tenth month to examine the matter."]]},
  {num:17,words:[["Ua latou faaiuina ona suesue i tagata uma e na fai avā i fafine ese i le uluai aso o le masina muamua.", "And they made an end with all the men that had taken strange wives by the first day of the first month."]]},
  {num:18,words:[["Ua iloa foi atalii o faitaulaga e na fai ava i fafine ese;", "And among the sons of the priests there were found that had taken strange wives:"], ["o isi atalii o Iosua le atalii o Iosataka ma ona uso,", "namely, of the sons of Jeshua the son of Jozadak,"], ["o Maaseia,", "and his brethren;"], ["ma Elisara,", "Maaseiah,"], ["ma Iaripi,", "and Eliezer, and Jarib,"], ["ma Ketalia.", "and Gedaliah."]]},
  {num:19,words:[["Ua latou tuuina atu o latou lima latou te aauina atu a latou avā;", "And they gave their hands that they would put away their wives; and being guilty,"], ["ona ua nofo sala foi i latou ua aumaia le mamoe poa mai le lafu ona o la latou agasala.", "they offered a ram of the flock for their trespass."]]},
  {num:20,words:[["O isi foi atalii o Imere;", "And of the sons of Immer;"], ["o Hanani,", "Hanani,"], ["ma Sepatia.", "and Zebadiah."]]},
  {num:21,words:[["O isi atalii o Harima;", "And of the sons of Harim;"], ["o Maaseia,", "Maaseiah,"], ["ma Elia,", "and Elijah,"], ["ma Semaia,", "and Shemaiah,"], ["ma Ikieli,", "and Jehiel,"], ["ma Usia.", "and Uzziah."]]},
  {num:22,words:[["O isi atalii o Pasura;", "And of the sons of Pashur;"], ["o Elioenai,", "Elioenai,"], ["o Maaseia,", "Maaseiah,"], ["o Isamaeli,", "Ishmael,"], ["o Natanielu,", "Nethaneel,"], ["o Iosapata,", "Jozabad,"], ["ma Eliasa.", "and Elasah."]]},
  {num:23,words:[["O isi foi o sa Levi;", "Also of the Levites;"], ["o Iosapata,", "Jozabad,"], ["ma Semi,", "and Shimei,"], ["ma Kilaia,", "and Kelaiah,"], ["o Kelita lea,", "(the same is Kelita,"], ["o Petakia,", ") Pethahiah,"], ["o Iuta,", "Judah,"], ["ma Elisara.", "and Eliezer."]]},
  {num:24,words:[["O lo le au pepese;", "Of the singers also;"], ["o Eliasipa. O isi foi o le au leoleo faitotoa;", "Eliashib:"], ["o Saluma,", "and of the porters; Shallum,"], ["ma Telema,", "and Telem,"], ["ma Auri.", "and Uri."]]},
  {num:25,words:[["O isi foi o Isaraelu;", "Moreover of Israel:"], ["o isi atalii o Parose;", "of the sons of Parosh;"], ["o Ramea,", "Ramiah,"], ["ma Iesia,", "and Jeziah,"], ["ma Malekia;", "and Malchiah,"], ["ma Meamina,", "and Miamin,"], ["ma Eleasaro,", "and Eleazar,"], ["ma Malekia,", "and Malchijah,"], ["ma Penaia.", "and Benaiah."]]},
  {num:26,words:[["O isi atalii o Elama;", "And of the sons of Elam;"], ["o Matania,", "Mattaniah,"], ["o Sakaria,", "Zechariah,"], ["ma Ieielu,", "and Jehiel,"], ["ma Opeti,", "and Abdi,"], ["ma Ieremota,", "and Jeremoth,"], ["ma Elia.", "and Eliah."]]},
  {num:27,words:[["O isi atalii o Satu;", "And of the sons of Zattu;"], ["o Elioenai,", "Elioenai,"], ["o Eliasipa,", "Eliashib,"], ["o Matania,", "Mattaniah,"], ["ma Ieremota,", "and Jeremoth,"], ["ma Sapata,", "and Zabad,"], ["ma Asesa.", "and Aziza."]]},
  {num:28,words:[["O isi atalii o Pepai;", "Of the sons also of Bebai;"], ["o Ioanaua,", "Jehohanan,"], ["o Hanania,", "Hananiah,"], ["o Sapai,", "Zabbai,"], ["ma Atalai.", "and Athlai."]]},
  {num:29,words:[["O isi atalii o Pani;", "And of the sons of Bani;"], ["o Mesulama,", "Meshullam,"], ["o Maluka,", "Malluch,"], ["ma Ataia,", "and Adaiah,"], ["o Iasuvi,", "Jashub,"], ["ma Seala,", "and Sheal,"], ["ma Ramota.", "and Ramoth."]]},
  {num:30,words:[["O isi atalii o Pakamoapi;", "And of the sons of Pahath-moab;"], ["o Atena,", "Adna,"], ["ma Kila,", "and Chelal,"], ["o Penaia,", "Benaiah,"], ["o Maaseia,", "Maaseiah,"], ["o Matania,", "Mattaniah,"], ["o Pesaleli,", "Bezaleel,"], ["ma Pinui,", "and Binnui,"], ["ma Manase.", "and Manasseh."]]},
  {num:31,words:[["O atalii foi o Harima,", "And of the sons of Harim;"], ["o Elisara,", "Eliezer,"], ["o Isea,", "Ishijah,"], ["o Malekia,", "Malchiah,"], ["o Semaia,", "Shemaiah,"], ["ma Simeona.", "Shimeon,"]]},
  {num:32,words:[["O Peniamina,", "Benjamin,"], ["o Maluka,", "Malluch,"], ["o Semaria.", "and Shemariah."]]},
  {num:33,words:[["O isi atalii o Hasumu;", "Of the sons of Hashum;"], ["o Matenai,", "Mattenai,"], ["o Matata,", "Mattathah,"], ["o Sapata,", "Zabad,"], ["o Elipelete,", "Eliphelet,"], ["o Ieremai,", "Jeremai,"], ["o Manase,", "Manasseh,"], ["ma Semi.", "and Shimei."]]},
  {num:34,words:[["O isi atalii o Pani;", "Of the sons of Bani;"], ["o Maatai,", "Maadai,"], ["o Amaramo,", "Amram,"], ["ma Ueli,", "and Uel,"]]},
  {num:35,words:[["o Penaia,", "Benaiah,"], ["o Petia,", "Bedeiah,"], ["o Kilui,", "Chelluh,"]]},
  {num:36,words:[["o Vania,", "Vaniah,"], ["o Meremota,", "Meremoth,"], ["o Eliasipa,", "Eliashib,"]]},
  {num:37,words:[["o Matania,", "Mattaniah,"], ["o Matenai,", "Mattenai,"], ["ma Iaasau,", "and Jaasau,"]]},
  {num:38,words:[["ma Pani,", "And Bani,"], ["ma Pinui,", "and Binnui,"], ["o Semi,", "Shimei,"]]},
  {num:39,words:[["ma Selemia,", "And Shelemiah,"], ["ma Natano,", "and Nathan,"], ["ma Ataia,", "and Adaiah,"]]},
  {num:40,words:[["o Makenatipai,", "Machnadebai,"], ["o Sasai,", "Shashai,"], ["o Sarai,", "Sharai,"]]},
  {num:41,words:[["o Asareelu,", "Azareel,"], ["ma Selemia,", "and Shelemiah,"], ["o Semaria,", "Shemariah,"]]},
  {num:42,words:[["o Saluma,", "Shallum,"], ["o Amaria,", "Amariah,"], ["ma Iosefa.", "and Joseph."]]},
  {num:43,words:[["O isi atalii o Nepo;", "Of the sons of Nebo;"], ["o Ieielu,", "Jeiel,"], ["o Matatia,", "Mattithiah,"], ["o Sapata,", "Zabad,"], ["o Sapina,", "Zebina,"], ["o Iatau,", "Jadau,"], ["ma Ioelu,", "and Joel,"], ["ma Penaia.", "Benaiah."]]},
  {num:44,words:[["O i latou uma ia na fai avā i fafine ese;", "All these had taken strange wives:"], ["na i ai foi i nisi o i latou o avā na latou fanaua tama.", "and some of them had wives by whom they had children."]]},
];
